input.content:
@startuml Fluxograma_Montar_Carro
!define PRIMARY # LightBlue
!define SUCCESS # LightGreen
!define WARNING # LightYellow
!define ERROR # LightCoral

skinparam backgroundColor white
skinparam activity {
    BackgroundColor PRIMARY
    BorderColor DarkBlue
    FontColor Black
}

title Fluxograma: Passo a Passo para Montar um Carro

start

:Início: Montagem de Carro;

partition "Fase 1: Preparação" {
    :Verificar lista de peças;
    :Organizar ferramentas;
    :Preparar área de trabalho;
}

partition "Fase 2: Chassi e Estrutura" {
    :Montar chassi principal;
    :Instalar suspensão dianteira;
    :Instalar suspensão traseira;
    :Montar sistema de freios;
}

partition "Fase 3: Motor e Transmissão" {
    :Preparar bloco do motor;
    :Instalar pistões e válvulas;
    :Conectar sistema de arrefecimento;
    :Instalar transmissão;
    :Conectar embreagem;
}

partition "Fase 4: Sistemas Elétricos" {
    :Instalar bateria;
    :Montar fiação principal;
    :Conectar sistema de ignição;
    :Instalar painel de instrumentos;
    :Conectar luzes e sinais;
}

partition "Fase 5: Carroçaria" {
    :Instalar portas;
    :Montar capô e bagageiro;
    :Instalar para-choques;
    :Colocar vidros;
    :Instalar interior;
}

partition "Fase 6: Acabamento" {
    :Adicionar fluidos;
    :Verificar níveis;
    :Testar sistemas elétricos;
    :Verificar pressão dos pneus;
}

repeat
    :Realizar testes finais;
    :Há problemas?;

repeat while (Sim) is (Sim) -> Não
    :Diagnosticar e corrigir;
backward:Diagnosticar e corrigir;

:Fim: Carro Pronto;

stop

@enduml

